callGraph.callee:
(async () => {
		try {
			const tabs = context.tabs ?? (await getDefaultTabsAdapter());
			const executionContext: AgentSessionLaunchContext = {
				...context,
				tabs,
			};
			phase = "launching";
			const payload =
				request.kind === "terminal"
					? await launchTerminalAdapter(request, executionContext)
					: await launchChatAdapter(request, executionContext);
			phase = "running";
			const result: AgentLaunchResult = {
				workspaceId: request.workspaceId,
				tabId: payload.tabId ?? null,
				paneId: payload.paneId ?? null,
				sessionId: payload.sessionId ?? null,
				status: phase,
				error: null,
			};
			captureLaunchEvent({
				context: executionContext,
				request,
				status: result.status,
				latencyMs: Date.now() - startedAt,
			});
			return result;
		} catch (error) {
			const executionContext: AgentSessionLaunchContext = {
				...context,
			};
			phase = "failed";
			const errorMessage = toErrorMessage(error);
			const result: AgentLaunchResult = {
				workspaceId: request.workspaceId,
				tabId: null,
				paneId: null,
				sessionId: null,
				status: phase,
				error: errorMessage,
			};
			captureLaunchEvent({
				context: executionContext,
				request,
				status: result.status,
				latencyMs: Date.now() - startedAt,
				error: errorMessage,
			});
			return result;
		}
	})
